import { StatusBar } from "../interaction/ui/statusBar.js";
import { Body2d } from "../simulation/body2d.js";
import { Vector2D } from "../util/vector2d.js";

//#region pointer (touch, mouse)
export interface Pointer {
    main: {
        state: ButtonState;
        downCoordinatesInSimSpace: Vector2D | undefined;
    };
    secondary: {
        state: ButtonState;
    };
    wheel: {
        state: ButtonState;
    };
}
export enum TouchAction {
    None = 0,
    AddBody = 1,
    ManipulateView = 2
}
export enum MouseAction {
    None = 0,
    AddBody = 1,
    Scroll = 2,
    Zoom = 3
}
export interface MultiTouchGesture {
    first: Vector2D;
    second: Vector2D;
    midpoint: Vector2D; 
    distance: number;
}
export interface Mouse {
   main: MouseButton;
   secondary: MouseButton;
   wheel: MouseButton;
}
export interface MouseButton {
    state: ButtonState;
    downCoordinatesInSimSpace?: { x: number, y: number } | Vector2D;
}
export enum ButtonState {
    Up = 0,
    Down = 1,
}
export enum MouseButtons {
    Main = 0,
    Wheel = 1,
    Secondary = 2,
}
//#endregion

//#region view and animation
export interface CanvasSpace {
    // use this to transform simulationSpace to canvasSpace and back
    origin: Vector2D, // the canvas' origin in simulation space
    currentZoom: number, // simulationUnits (meter) per canvasUnit
}
export interface AnimationSettings {
    frameLength: number; // ms
    displayVectors: boolean;
    tracePaths: boolean;
}
export interface UIAnimationSettings {
    displayVectors: boolean;
    tracePaths: boolean;
}
export interface CanvasLayer {
    canvas: HTMLCanvasElement;
    context: CanvasRenderingContext2D;
}
export type LayerName = 'background' | 'paths' | 'simulation' | 'interaction';
//#endregion

//#region user-input-related
export interface SimulationSettings {
    collisionDetection?: boolean;
    elasticCollisions?: boolean;
    gravitationalConstant?: number;
}

export interface ObjectState {
    body: Body2d, 
    position: Vector2D,
    velocity: Vector2D, // simulationUnits (meter) per second
    acceleration: Vector2D
}
//#endregion

//#region UI
export interface RadioButtonGroup {
    name: string;
    buttons: HTMLInputElement[];
}
export interface ContextMenuItem {
    label: string 
    action: () => void
    disabled?: boolean
    highlighted?: boolean
}
//#endregion

export interface PerformanceInfo {
    ticksLastSecond?: number,
    averageTicksPerSecond?: number
}